console.log("Background script running");chrome.runtime.onMessage.addListener((e,t,a)=>{if(e.action==="fetchImage")return o(e.url).then(r=>a({success:!0,data:r})).catch(r=>{console.warn("Failed to fetch image:",e.url,r.message),a({success:!1,error:r.message})}),!0});async function o(e){if(e.startsWith("data:"))return e;const t=await fetch(e,{mode:"cors",credentials:"omit"});if(!t.ok)throw new Error(`HTTP ${t.status}`);const a=await t.blob();return a.type,new Promise((r,s)=>{const n=new FileReader;n.onloadend=()=>r(n.result),n.onerror=()=>s(new Error("FileReader failed")),n.readAsDataURL(a)})}
